import { describe, it } from "vitest";

describe("MHPCO Claim Office - Premium Quote", () => {
  // 1. Empty item list
  it.todo("should charge 5 G for empty item list (only processing fee) -- 5 G");

  // 2. Single standard items (base premiums)
  it.todo("should charge 115 G for a standard sword (100 G base + 10 G first insurance + 5 G fee) -- 115 G");
  it.todo("should charge 71 G for a standard amulet (60 G base + 6 G first insurance + 5 G fee) -- 71 G");
  it.todo("should charge 93 G for a standard staff (80 G base + 8 G first insurance + 5 G fee) -- 93 G");
  it.todo("should charge 49 G for a standard potion (40 G base + 4 G first insurance + 5 G fee) -- 49 G");

  // 3. Components (base premiums and blocks of 3)
  it.todo("should charge 60 G for 2 runes (50 G base + 5 G first insurance + 5 G fee) -- 60 G");
  it.todo("should charge 71 G for 3 runes as a block (60 G base + 6 G first insurance + 5 G fee) -- 71 G");
  it.todo("should charge 115 G for 4 runes without a block (100 G base + 10 G first insurance + 5 G fee) -- 115 G");
  it.todo("should charge 198 G for 7 runes (175 G base + 17.5 G first insurance + 5 G fee, rounded up) -- 198 G");
  it.todo("should charge 88 G for 2 runes + 1 moonstone (75 G base + 7.5 G first insurance + 5 G fee, rounded up) -- 88 G");
  it.todo("should charge 137 G for 3 runes + 3 moonstones as two blocks (120 G base + 12 G first insurance + 5 G fee) -- 137 G");

  // 4. Item-specific modifiers (cursed, enchantment >= 5)
  it.todo("should charge 165 G for newcomer with a cursed sword (100 G base + 50 G curse + 10 G first insurance + 5 G fee) -- 165 G");
  it.todo("should charge 145 G for a highly enchanted sword with enchantment level 5 (100 G base + 30 G enchantment + 10 G first insurance + 5 G fee) -- 145 G");
  it.todo("should charge 115 G for a sword with enchantment level 4 (100 G base + 10 G first insurance + 5 G fee) -- 115 G");
  it.todo("should charge 195 G for a cursed and highly enchanted sword (100 G base + 50 G curse + 30 G enchantment + 10 G first insurance + 5 G fee) -- 195 G");

  // 5. Policy-wide modifiers (loyalty, follow-up contract)
  it.todo("should charge 95 G for a loyal customer of 2 years with a regular sword (100 G base + 10 G first insurance - 20 G loyalty + 5 G fee) -- 95 G");
  it.todo("should charge 100 G for a first-year customer's second contract with a regular sword (100 G base + 10 G first insurance - 15 G follow-up + 5 G fee) -- 100 G");
  it.todo("should charge 160 G for a long-standing customer's second contract with cursed sword of enchantment level 7 -- 160 G");
  it.todo("should charge 210 G before modifiers and fee for a cursed sword and plain amulet policy -- 210 G");
});

describe("MHPCO Claim Office - Claim Processing", () => {
  // 6. Standard reimbursement
  it.todo("should pay 400 G for damage of 500 G to a regular steel sword -- 400 G");
  it.todo("should pay 100 G for damage of 200 G to a rune -- 100 G");

  // 7. Special clauses (enchantment >= 8, dragon material)
  it.todo("should pay 700 G for damage of 800 G to a dragon-material sword of enchantment 5 (full reimbursement minus deductible) -- 700 G");
  it.todo("should pay 400 G for damage of 1000 G to a dragon-material sword of enchantment 9 (50% rate wins, then deductible) -- 400 G");
  it.todo("should pay 400 G for damage of 1000 G to a steel sword of enchantment 9 (50% rate wins, then deductible) -- 400 G");

  // 8. Deductible per damage event
  it.todo("should apply deductible once per damaged item for a policy covering a sword and an amulet -- 600 G");

  // 9. Multiple items of same type
  it.todo("should treat damages to multiple items of the same type as separate damages with their own deductibles -- 800 G");

  // 10. Cap exhaustion
  it.todo("should cap successive claims to twice the unmodified insurance value of the policy -- 1400 G then 600 G");

  // 11. Rounding in claim payouts
  it.todo("should round down final claim payout in MHPCO's favor if it yields a fraction -- 350 G");

  // 12. Edge cases and errors
  it.todo("should throw an error if quote includes an item with an unknown type -- error");
  it.todo("should throw an error if claim references a damage entry whose item is not part of the policy -- error");
  it.todo("should throw an error if claim contains a damage entry with a negative amount -- error");
  it.todo("should throw an error if claim contains more damages of a given type than the policy covers -- error");
});

