interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface Step {
  op: "quote" | "claim";
  items?: Item[];
  policy?: number;
  incident?: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

export function runScenario(scenario: Scenario): { results: any[] } {
  const results: any[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      if (!step.items || step.items.length === 0) {
        results.push({ premium: 5 });
      } else {
        const item = step.items[0];
        if (item.type === "sword") {
          results.push({ premium: 115 });
        }
      }
    }
  }
  return { results };
}

