input.content:
interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface Step {
  op: "quote" | "claim";
  items?: Item[];
  policy?: number;
  incident?: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function runScenario(scenario: Scenario): { results: any[] } {
  const results: any[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      if (!step.items || step.items.length === 0) {
        results.push({ premium: 5 });
      } else {
        let basePremium = 0;
        let curseSurcharge = 0;
        const mainItems: Item[] = [];
        const components: Record<string, number> = {};

        for (const item of step.items) {
          if (item.type === "rune" || item.type === "moonstone") {
            components[item.type] = (components[item.type] || 0) + 1;
          } else {
            mainItems.push(item);
          }
        }

        // Calculate main items base premium and modifiers
        for (const item of mainItems) {
          const itemBase = ITEM_BASE_PREMIUMS[item.type] || 0;
          basePremium += itemBase;
          if (item.cursed) {
            curseSurcharge += itemBase * 0.5;
          }
        }

        // Calculate components base premium with blocks of 3 alike components
        for (const [type, count] of Object.entries(components)) {
          if (count === 3) {
            basePremium += 60;
          } else {
            basePremium += count * 25;
          }
        }

        // Standard: 10% first insurance surcharge, 5 G fee
        // All amounts are rounded to whole G in MHPCO's favor (so premium mods rounded up at the very end when sum is calculated)
        const premium = Math.ceil(basePremium + curseSurcharge + (basePremium * 0.1)) + 5;
        results.push({ premium });
      }
    }
  }
  return { results };
}

