interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface Step {
  op: "quote" | "claim";
  items?: Item[];
  policy?: number;
  incident?: {
    cause: string;
    damages: { itemType: string; amount: number }[];
  };
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const ITEM_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

interface CreatedPolicy {
  items: Item[];
  cap: number;
}

export function runScenario(scenario: Scenario): { results: any[] } {
  const results: any[] = [];
  let quoteCount = 0;
  const policies: CreatedPolicy[] = [];

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      if (!step.items || step.items.length === 0) {
        results.push({ premium: 5 });
        policies.push({ items: [], cap: 0 });
      } else {
        quoteCount++;
        let basePremium = 0;
        let itemSurcharges = 0;
        const mainItems: Item[] = [];
        const components: Record<string, number> = {};

        let insuranceSum = 0;

        for (const item of step.items) {
          if (item.type === "rune" || item.type === "moonstone") {
            components[item.type] = (components[item.type] || 0) + 1;
            insuranceSum += ITEM_VALUES[item.type] || 250;
          } else {
            mainItems.push(item);
            insuranceSum += ITEM_VALUES[item.type] || 0;
          }
        }

        // Calculate main items base premium and modifiers
        for (const item of mainItems) {
          const itemBase = ITEM_BASE_PREMIUMS[item.type] || 0;
          basePremium += itemBase;
          if (item.cursed) {
            itemSurcharges += itemBase * 0.5;
          }
          if (item.enchantment !== undefined && item.enchantment >= 5) {
            itemSurcharges += itemBase * 0.3;
          }
        }

        // Calculate components base premium with blocks of 3 alike components
        for (const [type, count] of Object.entries(components)) {
          if (count === 3) {
            basePremium += 60;
          } else {
            basePremium += count * 25;
          }
        }

        // Policy-wide modifiers
        let policyModifiers = 0;
        if (scenario.customer.yearsWithMHPCO >= 2) {
          policyModifiers -= basePremium * 0.2;
        }
        policyModifiers += basePremium * 0.1;
        if (quoteCount > 1) {
          policyModifiers -= basePremium * 0.15;
        }

        const premium = Math.ceil(basePremium + itemSurcharges + policyModifiers) + 5;
        results.push({ premium });

        policies.push({
          items: step.items,
          cap: insuranceSum * 2
        });
      }
    } else if (step.op === "claim") {
      const policyIndex = step.policy ?? 0;
      const policy = policies[policyIndex];
      if (policy && step.incident && step.incident.damages) {
        let totalPayout = 0;
        for (const damage of step.incident.damages) {
          // Standard reimbursement: full reimbursement minus 100 G deductible
          let payout = damage.amount - 100;
          if (payout < 0) {
            payout = 0;
          }
          totalPayout += payout;
        }

        if (totalPayout > policy.cap) {
          totalPayout = policy.cap;
        }
        policy.cap -= totalPayout;

        results.push({
          payout: Math.floor(totalPayout),
          remainingCap: policy.cap
        });
      }
    }
  }
  return { results };
}

