it("should pay 100 G for damage of 200 G to a rune -- 100 G", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      { op: "quote", items: [{ type: "rune" }] }, // Policy 0 (Value: 250 G, Cap: 500 G)
      {
        op: "claim",
